# ---- numpy encoder helper (robust JSON) ----
def numpy_encoder(obj):
    try:
        import numpy as _np
        if isinstance(obj, (_np.integer,)):
            return int(obj)
        if isinstance(obj, (_np.floating,)):
            return float(obj)
        if isinstance(obj, _np.ndarray):
            return obj.tolist()
    except Exception:
        pass
    # Allow datetime-like, etc.
    try:
        return obj.__json__()
    except Exception:
        pass
    return str(obj)


class NozzlePositionChecklistStore:
    """
    Manifest-backed image/metadata recorder for NozzlePositionCalibrationProcess.
    Saves captures under:
      FreeRTOS-interface/CalibrationClasses/test_images/NozzlePositionCalibrationProcess/
    """

    PROCESS_NAME = "NozzlePositionCalibrationProcess"

    def __init__(
        self,
        model,
        *,
        process_name: str | None = None,
        base_dir: str | None = None,
        manifest_path: str | None = None,
    ):
        self.model = model
        self.process_name = process_name or self.PROCESS_NAME
        self.base_dir = os.path.abspath(
            base_dir
            or os.path.join(os.path.dirname(os.path.abspath(__file__)), "test_images", self.process_name)
        )
        self.manifest_path = os.path.abspath(
            manifest_path or os.path.join(self.base_dir, "checklist_manifest.v1.json")
        )

        self.manifest = None
        self.rows = []
        self._row_map = {}

        self.session_id = None
        self.session_dir = None
        self.images_dir = None
        self.records_path = None
        self.session_meta_path = None

        self._capture_records = []
        self._capture_by_id = {}
        self._rejected_ids = set()
        self._last_capture_record_id = None

        os.makedirs(self.base_dir, exist_ok=True)
        self.load_manifest()

    @staticmethod
    def validate_manifest(manifest: dict):
        if not isinstance(manifest, dict):
            raise ValueError("Checklist manifest must be a JSON object.")
        if int(manifest.get("schema_version", -1)) != 1:
            raise ValueError("Checklist manifest schema_version must be 1.")
        if str(manifest.get("process_name", "")).strip() == "":
            raise ValueError("Checklist manifest missing process_name.")

        cases = manifest.get("cases")
        if not isinstance(cases, list) or not cases:
            raise ValueError("Checklist manifest must define non-empty 'cases'.")

        seen_case_ids = set()
        for case in cases:
            case_id = str(case.get("case_id", "")).strip()
            if not case_id:
                raise ValueError("Checklist case missing case_id.")
            if case_id in seen_case_ids:
                raise ValueError(f"Duplicate checklist case_id: {case_id}")
            seen_case_ids.add(case_id)

            steps = case.get("steps")
            if not isinstance(steps, list) or not steps:
                raise ValueError(f"Checklist case '{case_id}' must define non-empty steps.")

            seen_step_ids = set()
            for step in steps:
                step_id = str(step.get("step_id", "")).strip()
                if not step_id:
                    raise ValueError(f"Checklist case '{case_id}' has step with missing step_id.")
                if step_id in seen_step_ids:
                    raise ValueError(f"Checklist case '{case_id}' has duplicate step_id '{step_id}'.")
                seen_step_ids.add(step_id)

                req = step.get("required", {})
                if not isinstance(req, dict):
                    raise ValueError(f"Checklist case '{case_id}' step '{step_id}' required must be an object.")
                for role in ("background", "droplet"):
                    v = req.get(role, None)
                    if v is None:
                        continue
                    if int(v) < 0:
                        raise ValueError(
                            f"Checklist case '{case_id}' step '{step_id}' has invalid required count for {role}."
                        )

    def load_manifest(self):
        if not os.path.exists(self.manifest_path):
            raise FileNotFoundError(f"Checklist manifest not found: {self.manifest_path}")
        with open(self.manifest_path, "r", encoding="utf-8") as f:
            data = json.load(f)
        self.validate_manifest(data)

        self.manifest = data
        self.rows = self._flatten_rows(data)
        self._row_map = {r["row_key"]: r for r in self.rows}
        return self.manifest

    def _flatten_rows(self, manifest: dict):
        defaults = manifest.get("defaults", {}) or {}
        bg_default = max(0, int(defaults.get("background_replicates_min", 1)))
        dr_default = max(0, int(defaults.get("droplet_replicates_min", 3)))

        rows = []
        for case in manifest.get("cases", []):
            case_id = str(case.get("case_id", "")).strip()
            case_label = str(case.get("label", case_id)).strip() or case_id
            case_tip = str(case.get("tooltip", "")).strip()
            steps = case.get("steps", []) or []

            for idx, step in enumerate(steps):
                step_id = str(step.get("step_id", "")).strip() or f"step_{idx+1}"
                step_label = str(step.get("label", step_id)).strip() or step_id
                step_tip = str(step.get("tooltip", "")).strip()
                req = step.get("required", {}) or {}
                bg_req = max(0, int(req.get("background", bg_default)))
                dr_req = max(0, int(req.get("droplet", dr_default)))
                expected_status = str(step.get("expected_status", case.get("expected_status", ""))).strip()
                expected_decision = str(step.get("expected_decision", case.get("expected_decision", ""))).strip()

                row_key = f"{case_id}:{step_id}"
                rows.append(
                    {
                        "row_key": row_key,
                        "case_id": case_id,
                        "case_label": case_label,
                        "case_tooltip": case_tip,
                        "step_id": step_id,
                        "step_label": step_label,
                        "step_tooltip": step_tip,
                        "required_background": bg_req,
                        "required_droplet": dr_req,
                        "expected_status": expected_status,
                        "expected_decision": expected_decision,
                        "tooltip": step_tip or case_tip or step_label,
                    }
                )
        return rows

    def begin_session(self, *, session_id: str | None = None):
        ts = datetime.now().strftime("%Y%m%d_%H%M%S")
        self.session_id = session_id or f"session_{ts}"
        self.session_dir = os.path.join(self.base_dir, self.session_id)
        self.images_dir = os.path.join(self.session_dir, "images")
        self.records_path = os.path.join(self.session_dir, "records.jsonl")
        self.session_meta_path = os.path.join(self.session_dir, "session_meta.json")

        os.makedirs(self.images_dir, exist_ok=True)

        self._capture_records = []
        self._capture_by_id = {}
        self._rejected_ids = set()
        self._last_capture_record_id = None

        meta = {
            "schema_version": 1,
            "process_name": self.process_name,
            "manifest_path": os.path.relpath(self.manifest_path, self.session_dir).replace("\\", "/"),
            "manifest_schema_version": int((self.manifest or {}).get("schema_version", 1)),
            "session_id": self.session_id,
            "started_at": datetime.now(timezone.utc).isoformat().replace("+00:00", "Z"),
        }
        with open(self.session_meta_path, "w", encoding="utf-8") as f:
            json.dump(meta, f, indent=2)
        return self.session_dir

    def ensure_session(self):
        if self.session_dir is None:
            self.begin_session()

    def get_rows(self):
        return list(self.rows)

    def get_row(self, row_key: str):
        return self._row_map.get(str(row_key))

    def resolve_reagent_name(self) -> str:
        try:
            ph = self.model.rack_model.get_gripper_printer_head()
            if ph is None:
                return "unknown"
            stock = ph.get_stock_solution()
            name = getattr(stock, "reagent_name", None)
            if name:
                return str(name)
            return str(stock) if stock is not None else "unknown"
        except Exception:
            return "unknown"

    def _append_record(self, payload: dict):
        self.ensure_session()
        with open(self.records_path, "a", encoding="utf-8") as f:
            f.write(json.dumps(payload, default=numpy_encoder) + "\n")

    def _prepare_image_for_write(self, image):
        arr = np.asarray(image)
        if arr.ndim == 2:
            return arr
        if arr.ndim == 3 and arr.shape[2] == 3:
            # UI frames are RGB; OpenCV writer expects BGR.
            return cv2.cvtColor(arr, cv2.COLOR_RGB2BGR)
        if arr.ndim == 3 and arr.shape[2] == 4:
            return cv2.cvtColor(arr, cv2.COLOR_RGBA2BGRA)
        raise ValueError(f"Unsupported image shape for write: {arr.shape}")

    def _accepted_count(self, row_key: str, role: str) -> int:
        count = 0
        for rec in self._capture_records:
            if rec.get("row_key") != row_key:
                continue
            if rec.get("capture_role") != role:
                continue
            rid = rec.get("record_id")
            if rid in self._rejected_ids:
                continue
            count += 1
        return count

    def capture_for_row(
        self,
        row_key: str,
        capture_role: str,
        image,
        *,
        selected_label: str,
        machine_state: dict | None = None,
        camera_settings: dict | None = None,
        reagent_name: str | None = None,
        fsm_hint: str | None = None,
        operator_note: str | None = None,
        pair_id: str | None = None,
        pair_role: str | None = None,
        pair_order: int | None = None,
        pair_capture_mode: str | None = None,
        subtract_background_record_id: str | None = None,
        subtract_background_image_relpath: str | None = None,
    ):
        self.ensure_session()
        role = str(capture_role).lower().strip()
        if role not in ("background", "droplet"):
            raise ValueError(f"Unsupported capture role: {capture_role}")
        row = self.get_row(row_key)
        if row is None:
            raise KeyError(f"Unknown checklist row key: {row_key}")

        idx = self._accepted_count(row_key, role) + 1
        stamp = datetime.now(timezone.utc).strftime("%Y%m%dT%H%M%S_%f")
        filename = f"{stamp}_{role}_{idx:03d}.jpg"
        relpath = os.path.join("images", row["case_id"], row["step_id"], role, filename)
        relpath = relpath.replace("\\", "/")
        abspath = os.path.join(self.session_dir, *relpath.split("/"))
        os.makedirs(os.path.dirname(abspath), exist_ok=True)

        out = self._prepare_image_for_write(image)
        ok = cv2.imwrite(abspath, out)
        if not ok:
            raise IOError(f"Failed to write capture image: {abspath}")

        record_id = str(uuid.uuid4())
        payload = {
            "type": "capture",
            "record_id": record_id,
            "timestamp_utc": datetime.now(timezone.utc).isoformat().replace("+00:00", "Z"),
            "session_id": self.session_id,
            "process_name": self.process_name,
            "row_key": row["row_key"],
            "case_id": row["case_id"],
            "case_label": row["case_label"],
            "step_id": row["step_id"],
            "step_label": row["step_label"],
            "selected_label": str(selected_label),
            "capture_role": role,
            "image_relpath": relpath,
            "required_background": int(row["required_background"]),
            "required_droplet": int(row["required_droplet"]),
            "expected_status": row.get("expected_status"),
            "expected_decision": row.get("expected_decision"),
            "machine_state": machine_state or {},
            "camera_settings": camera_settings or {},
            "reagent_name": str(reagent_name or "unknown"),
            "fsm_hint": str(fsm_hint or ""),
            "operator_note": str(operator_note or ""),
            # Pair metadata enables deterministic background subtraction matching during analysis.
            "pair_id": str(pair_id or ""),
            "pair_role": str(pair_role or ""),
            "pair_order": int(pair_order) if pair_order is not None else None,
            "pair_capture_mode": str(pair_capture_mode or ""),
            "subtract_background_record_id": str(subtract_background_record_id or ""),
            "subtract_background_image_relpath": str(subtract_background_image_relpath or ""),
            "rejected": False,
        }
        self._append_record(payload)
        self._capture_records.append(payload)
        self._capture_by_id[record_id] = payload
        self._last_capture_record_id = record_id
        return payload

    def reject_last_capture(self, *, reason: str = ""):
        self.ensure_session()
        rid = self._last_capture_record_id
        if not rid:
            return None
        if rid in self._rejected_ids:
            return None

        self._rejected_ids.add(rid)
        if rid in self._capture_by_id:
            self._capture_by_id[rid]["rejected"] = True
            self._capture_by_id[rid]["rejected_at"] = (
                datetime.now(timezone.utc).isoformat().replace("+00:00", "Z")
            )

        evt = {
            "type": "reject",
            "timestamp_utc": datetime.now(timezone.utc).isoformat().replace("+00:00", "Z"),
            "session_id": self.session_id,
            "target_record_id": rid,
            "reason": str(reason or ""),
        }
        self._append_record(evt)
        return evt

    def get_row_status(self, row_key: str):
        row = self.get_row(row_key)
        if row is None:
            raise KeyError(f"Unknown checklist row key: {row_key}")
        bg = self._accepted_count(row_key, "background")
        dr = self._accepted_count(row_key, "droplet")
        complete = (bg >= int(row["required_background"])) and (dr >= int(row["required_droplet"]))
        return {
            "row_key": row_key,
            "accepted_background": bg,
            "accepted_droplet": dr,
            "required_background": int(row["required_background"]),
            "required_droplet": int(row["required_droplet"]),
            "complete": bool(complete),
        }

    def get_all_status(self):
        out = {}
        for row in self.rows:
            out[row["row_key"]] = self.get_row_status(row["row_key"])
        return out

    def is_complete(self) -> bool:
        statuses = self.get_all_status()
        return all(s.get("complete", False) for s in statuses.values())


class CalibrationProcessRecorder:
    """
    Per-process recorder for calibration runs.
    Stores raw captures, structured events, analysis payloads, and operator verdict.
    """

    SCHEMA_VERSION = 1
    CAPTURE_WRITE_DRAIN_TIMEOUT_S = 5.0

    def __init__(self, model):
        self.model = model
        self._lock = threading.Lock()
        self._capture_write_condition = threading.Condition(self._lock)
        self._active = None
        self._last = None
        self._capture_write_queue = None
        self._capture_write_stop_evt = None
        self._capture_write_thread = None

    @staticmethod
    def _now_utc() -> str:
        return datetime.now(timezone.utc).isoformat().replace("+00:00", "Z")

    @staticmethod
    def _write_json_atomic(path: str, payload: dict):
        tmp = path + ".tmp"
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(payload, f, indent=2, default=numpy_encoder)
            f.flush()
            os.fsync(f.fileno())
        os.replace(tmp, path)

    @staticmethod
    def _append_jsonl(path: str, payload: dict):
        with open(path, "a", encoding="utf-8") as f:
            f.write(json.dumps(payload, default=numpy_encoder) + "\n")

    @staticmethod
    def _prepare_image_for_write(image):
        arr = np.asarray(image)
        if arr.ndim == 2:
            return arr
        if arr.ndim == 3 and arr.shape[2] == 3:
            return cv2.cvtColor(arr, cv2.COLOR_RGB2BGR)
        if arr.ndim == 3 and arr.shape[2] == 4:
            return cv2.cvtColor(arr, cv2.COLOR_RGBA2BGRA)
        raise ValueError(f"Unsupported image shape for write: {arr.shape}")

    @staticmethod
    def _copy_image_for_queue(image):
        arr = np.asarray(image)
        if arr.ndim == 2:
            return arr.copy()
        if arr.ndim == 3 and arr.shape[2] in (3, 4):
            return arr.copy()
        raise ValueError(f"Unsupported image shape for write: {arr.shape}")

    def _default_root_dir(self) -> str:
        exp = getattr(self.model, "experiment_model", None)
        exp_dir = getattr(exp, "experiment_dir_path", None)
        if exp_dir:
            return os.path.abspath(os.path.join(exp_dir, "calibration_recordings"))
        cal_path = getattr(exp, "calibration_file_path", None)
        if cal_path:
            return os.path.abspath(os.path.join(os.path.dirname(cal_path), "calibration_recordings"))
        return os.path.abspath(os.path.join(os.getcwd(), "calibration_recordings"))

    def _active_or_last(self):
        return self._active or self._last

    def get_active_run_dir(self) -> str | None:
        with self._lock:
            if not self._active:
                return None
            return self._active["run_dir"]

    def get_last_run_dir(self) -> str | None:
        with self._lock:
            if not self._last:
                return None
            return self._last["run_dir"]

    def _append_event_locked(
        self,
        run: dict,
        event_type: str,
        payload: dict | None = None,
        *,
        state_name: str | None = None,
        level: str = "info",
    ) -> dict:
        run["event_index"] = int(run.get("event_index", 0)) + 1
        evt = {
            "schema_version": int(self.SCHEMA_VERSION),
            "event_id": str(uuid.uuid4()),
            "event_index": int(run["event_index"]),
            "ts_utc": self._now_utc(),
            "run_id": run["run_id"],
            "process_name": run["process_name"],
            "phase_name": run["phase_name"],
            "event_type": str(event_type),
            "state_name": str(state_name or ""),
            "level": str(level),
            "payload": payload or {},
        }
        self._append_jsonl(run["events_path"], evt)
        return evt

    def _append_recorder_warning_locked(self, run: dict, warning: dict):
        warnings = [dict(item or {}) for item in list(run.get("recorder_warnings") or [])]
        warnings.append(dict(warning or {}))
        run["recorder_warnings"] = warnings
        run["recorder_warning_count"] = int(len(warnings))

    def _append_capture_write_failure_locked(self, run: dict, failure: dict):
        failures = [dict(item or {}) for item in list(run.get("capture_write_failures") or [])]
        failures.append(dict(failure or {}))
        run["capture_write_failures"] = failures
        run["capture_write_failure_count"] = int(len(failures))

    def _capture_write_worker(self, run: dict):
        while True:
            stop_evt = self._capture_write_stop_evt
            work_queue = self._capture_write_queue
            if stop_evt is None or work_queue is None:
                break
            try:
                if stop_evt.is_set():
                    job = work_queue.get_nowait()
                else:
                    job = work_queue.get(timeout=0.1)
            except queue.Empty:
                if stop_evt is not None and stop_evt.is_set():
                    break
                continue

            capture_ref = dict(job.get("capture_ref") or {})
            try:
                out = self._prepare_image_for_write(job.get("image"))
                ok = cv2.imwrite(str(job.get("abspath")), out)
                if not ok:
                    raise IOError(f"Failed to write capture image: {job.get('abspath')}")
                event_payload = {
                    "capture_id": capture_ref.get("capture_id"),
                    "capture_role": capture_ref.get("capture_role"),
                    "image_relpath": capture_ref.get("image_relpath"),
                    "metadata": dict(job.get("metadata") or {}),
                }
                with self._lock:
                    self._append_event_locked(run, "capture_saved", event_payload)
            except Exception as exc:
                failure_payload = {
                    "capture_id": capture_ref.get("capture_id"),
                    "capture_role": capture_ref.get("capture_role"),
                    "image_relpath": capture_ref.get("image_relpath"),
                    "metadata": dict(job.get("metadata") or {}),
                    "error_message": str(exc),
                }
                with self._lock:
                    self._append_capture_write_failure_locked(run, failure_payload)
                    self._append_event_locked(
                        run,
                        "capture_save_failed",
                        failure_payload,
                        level="warning",
                    )
            finally:
                try:
                    work_queue.task_done()
                except Exception:
                    pass
                with self._capture_write_condition:
                    pending = int(run.get("pending_capture_write_count", 0)) - 1
                    run["pending_capture_write_count"] = int(max(0, pending))
                    self._capture_write_condition.notify_all()

    def _wait_for_pending_capture_writes(self, run: dict, *, timeout_s: float):
        deadline = time.monotonic() + max(0.0, float(timeout_s))
        with self._capture_write_condition:
            while True:
                pending = int(run.get("pending_capture_write_count", 0))
                if pending <= 0:
                    return True, 0
                remaining = float(deadline - time.monotonic())
                if remaining <= 0.0:
                    return False, pending
                self._capture_write_condition.wait(timeout=remaining)

    def _stop_capture_write_worker(self):
        with self._lock:
            stop_evt = self._capture_write_stop_evt
            thread = self._capture_write_thread
        if stop_evt is not None:
            stop_evt.set()
        if thread is not None:
            thread.join()
        with self._lock:
            self._capture_write_thread = None
            self._capture_write_stop_evt = None
            self._capture_write_queue = None

    def start_run(self, process_name: str, phase_name: str, *, extra_meta: dict | None = None):
        with self._lock:
            ts = datetime.now().strftime("%Y%m%d_%H%M%S")
            run_id = f"run_{ts}_{uuid.uuid4().hex[:8]}"
            root = self._default_root_dir()
            run_dir = os.path.join(root, str(process_name), run_id)
            captures_dir = os.path.join(run_dir, "captures")
            os.makedirs(captures_dir, exist_ok=True)

            run = {
                "run_id": run_id,
                "process_name": str(process_name),
                "phase_name": str(phase_name),
                "run_dir": run_dir,
                "captures_dir": captures_dir,
                "events_path": os.path.join(run_dir, "events.jsonl"),
                "analysis_path": os.path.join(run_dir, "analysis.jsonl"),
                "meta_path": os.path.join(run_dir, "run_meta.json"),
                "verdict_path": os.path.join(run_dir, "verdict.json"),
                "capture_index": 0,
                "event_index": 0,
            }

            meta = {
                "schema_version": int(self.SCHEMA_VERSION),
                "run_id": run_id,
                "process_name": str(process_name),
                "phase_name": str(phase_name),
                "started_at_utc": self._now_utc(),
                "ended_at_utc": None,
                "outcome": "running",
                "error_message": "",
                "recorder_warning_count": 0,
                "recorder_warnings": [],
                "capture_write_failure_count": 0,
                "capture_write_failures": [],
            }
            if isinstance(extra_meta, dict):
                meta.update(extra_meta)

            verdict = {
                "schema_version": int(self.SCHEMA_VERSION),
                "run_id": run_id,
                "process_name": str(process_name),
                "phase_name": str(phase_name),
                "outcome": "unknown",
                "failure_summary": "",
                "suspected_cause": "",
                "notes": "",
                "submitted_by": "system",
                "submitted_at_utc": self._now_utc(),
            }

            self._write_json_atomic(run["meta_path"], meta)
            self._write_json_atomic(run["verdict_path"], verdict)

            run["pending_capture_write_count"] = 0
            run["recorder_warning_count"] = 0
            run["recorder_warnings"] = []
            run["capture_write_failure_count"] = 0
            run["capture_write_failures"] = []

            self._capture_write_queue = queue.Queue()
            self._capture_write_stop_evt = threading.Event()
            self._capture_write_thread = threading.Thread(
                target=self._capture_write_worker,
                args=(run,),
                daemon=True,
            )
            self._active = run
            self._last = dict(run)
            thread = self._capture_write_thread
            run_dir_out = run_dir

        if thread is not None:
            thread.start()
        return run_dir_out

    def append_event(
        self,
        event_type: str,
        payload: dict | None = None,
        *,
        state_name: str | None = None,
        level: str = "info",
    ) -> dict | None:
        with self._lock:
            if not self._active:
                return None
            return self._append_event_locked(
                self._active,
                str(event_type),
                payload or {},
                state_name=state_name,
                level=level,
            )

    def append_analysis(self, record: dict) -> dict | None:
        with self._lock:
            if not self._active:
                return None
            payload = dict(record or {})
            payload.setdefault("schema_version", int(self.SCHEMA_VERSION))
            payload.setdefault("analysis_id", str(uuid.uuid4()))
            payload.setdefault("ts_utc", self._now_utc())
            payload.setdefault("run_id", self._active["run_id"])
            payload.setdefault("process_name", self._active["process_name"])
            payload.setdefault("phase_name", self._active["phase_name"])
            self._append_jsonl(self._active["analysis_path"], payload)
            return payload

    def save_capture_image(
        self,
        image,
        *,
        role: str = "capture",
        file_ext: str = "jpg",
        metadata: dict | None = None,
    ) -> dict | None:
        with self._lock:
            if not self._active:
                return None
            run = self._active
            run["capture_index"] = int(run.get("capture_index", 0)) + 1
            idx = int(run["capture_index"])
            capture_id = f"cap_{idx:06d}"
            ext = str(file_ext or "jpg").lstrip(".").lower()
            filename = f"{capture_id}_{str(role)}.{ext}"
            abspath = os.path.join(run["captures_dir"], filename)
            relpath = os.path.join("captures", filename).replace("\\", "/")
            queued_image = self._copy_image_for_queue(image)
            h = int(queued_image.shape[0]) if hasattr(queued_image, "shape") and len(queued_image.shape) >= 2 else None
            w = int(queued_image.shape[1]) if hasattr(queued_image, "shape") and len(queued_image.shape) >= 2 else None
            info = {
                "capture_id": capture_id,
                "capture_index": idx,
                "capture_role": str(role),
                "image_relpath": relpath,
                "width": w,
                "height": h,
                "captured_at_utc": self._now_utc(),
            }
            if isinstance(metadata, dict):
                info.update(metadata)
            run["pending_capture_write_count"] = int(run.get("pending_capture_write_count", 0)) + 1
            write_queue = self._capture_write_queue
            job = {
                "capture_ref": dict(info),
                "metadata": dict(metadata or {}),
                "image": queued_image,
                "abspath": abspath,
            }
            if write_queue is None:
                run["pending_capture_write_count"] = int(max(0, run["pending_capture_write_count"] - 1))
                raise RuntimeError("Capture writer queue is unavailable.")
            try:
                write_queue.put_nowait(job)
            except Exception:
                run["pending_capture_write_count"] = int(max(0, run["pending_capture_write_count"] - 1))
                self._capture_write_condition.notify_all()
                raise
            return info

    def finalize_run(self, outcome: str, *, error_message: str = ""):
        with self._lock:
            if not self._active:
                return
            run = self._active
            meta_path = run["meta_path"]

        drained, pending = self._wait_for_pending_capture_writes(
            run,
            timeout_s=float(self.CAPTURE_WRITE_DRAIN_TIMEOUT_S),
        )
        if not drained:
            with self._lock:
                warning_payload = {
                    "kind": "capture_write_drain_timeout",
                    "pending_capture_write_count": int(pending),
                    "drain_timeout_s": float(self.CAPTURE_WRITE_DRAIN_TIMEOUT_S),
                }
                self._append_recorder_warning_locked(run, warning_payload)
                self._append_event_locked(
                    run,
                    "capture_write_drain_timeout",
                    warning_payload,
                    level="warning",
                )

        self._stop_capture_write_worker()

        with self._lock:
            try:
                with open(meta_path, "r", encoding="utf-8") as f:
                    meta = json.load(f)
            except Exception:
                meta = {
                    "schema_version": int(self.SCHEMA_VERSION),
                    "run_id": run["run_id"],
                    "process_name": run["process_name"],
                    "phase_name": run["phase_name"],
                    "started_at_utc": "",
                }
            meta["ended_at_utc"] = self._now_utc()
            meta["outcome"] = str(outcome)
            meta["error_message"] = str(error_message or "")
            meta["recorder_warning_count"] = int(run.get("recorder_warning_count", 0))
            meta["recorder_warnings"] = [dict(item or {}) for item in list(run.get("recorder_warnings") or [])]
            meta["capture_write_failure_count"] = int(run.get("capture_write_failure_count", 0))
            meta["capture_write_failures"] = [
                dict(item or {}) for item in list(run.get("capture_write_failures") or [])
            ]
            self._write_json_atomic(meta_path, meta)
            self._last = dict(run)
            self._active = None

    def write_verdict(
        self,
        outcome: str,
        *,
        failure_summary: str = "",
        suspected_cause: str = "",
        notes: str = "",
        submitted_by: str = "ui",
    ):
        with self._lock:
            run = self._active_or_last()
            if not run:
                return None
            verdict = {
                "schema_version": int(self.SCHEMA_VERSION),
                "run_id": run["run_id"],
                "process_name": run["process_name"],
                "phase_name": run["phase_name"],
                "outcome": str(outcome or "unknown"),
                "failure_summary": str(failure_summary or ""),
                "suspected_cause": str(suspected_cause or ""),
                "notes": str(notes or ""),
                "submitted_by": str(submitted_by or "ui"),
                "submitted_at_utc": self._now_utc(),
            }
            self._write_json_atomic(run["verdict_path"], verdict)
            return verdict


class RefuelDatasetCaptureStore:
    """
    Run-scoped recorder for refuel-level dataset capture.
    Keeps scene/frame manifests beside raw captures while reusing CalibrationProcessRecorder.
    """

    PROCESS_NAME = "RefuelLevelDatasetCaptureProcess"
    PHASE_NAME = "refuel_level_dataset_capture"
    SCHEMA_VERSION = 1

    def __init__(self, model, *, process_name=None, phase_name=None):
        self.model = model
        self.process_name = str(process_name or self.PROCESS_NAME)
        self.phase_name = str(phase_name or self.PHASE_NAME)
        self.recorder = CalibrationProcessRecorder(model)
        self.reset_state()

    @staticmethod
    def _now_utc():
        return datetime.now(timezone.utc).isoformat().replace("+00:00", "Z")

    @staticmethod
    def _write_jsonl_atomic(path, rows):
        tmp = path + ".tmp"
        with open(tmp, "w", encoding="utf-8") as handle:
            for row in rows:
                handle.write(json.dumps(row, default=numpy_encoder) + "\n")
            handle.flush()
            os.fsync(handle.fileno())
        os.replace(tmp, path)

    @staticmethod
    def _touch_file(path):
        os.makedirs(os.path.dirname(path), exist_ok=True)
        if not os.path.exists(path):
            with open(path, "w", encoding="utf-8"):
                pass

    @staticmethod
    def _dedupe_tags(tags):
        out = []
        seen = set()
        for raw in tags or []:
            value = str(raw or "").strip()
            if not value:
                continue
            lowered = value.lower()
            if lowered in seen:
                continue
            seen.add(lowered)
            out.append(value)
        return out

    @staticmethod
    def _json_copy(payload):
        return json.loads(json.dumps(payload or {}, default=numpy_encoder))

    def reset_state(self):
        self.run_dir = None
        self.last_run_dir = None
        self.scenes_path = None
        self.frames_path = None
        self.labels_path = None
        self._scene_records = []
        self._frame_records = []
        self._frames_by_id = {}
        self._current_scene = None
        self._last_frame_id = None
        self._scene_index = 0
        self._sequence_index = 0
        self._session_meta = {}

    def is_active(self):
        return bool(self.run_dir)

    def get_run_dir(self):
        return self.run_dir or self.last_run_dir

    def get_current_scene(self):
        return dict(self._current_scene) if self._current_scene else None

    def get_frame_records(self, *, accepted_only=False):
        rows = list(self._frame_records)
        if accepted_only:
            rows = [row for row in rows if not bool(row.get("rejected"))]
        return [dict(row) for row in rows]

    def _sync_scene_file(self):
        if self.scenes_path:
            self._write_jsonl_atomic(self.scenes_path, self._scene_records)

    def _sync_frame_file(self):
        if self.frames_path:
            self._write_jsonl_atomic(self.frames_path, self._frame_records)

    def _append_event(self, event_type, payload=None):
        evt = self.recorder.append_event(str(event_type), payload or {})
        if evt is None and self.run_dir:
            path = os.path.join(self.run_dir, "events.jsonl")
            row = {
                "schema_version": int(self.SCHEMA_VERSION),
                "event_id": str(uuid.uuid4()),
                "event_index": None,
                "ts_utc": self._now_utc(),
                "run_id": self._session_meta.get("run_id", ""),
                "process_name": self.process_name,
                "phase_name": self.phase_name,
                "event_type": str(event_type),
                "state_name": "",
                "level": "info",
                "payload": payload or {},
            }
            with open(path, "a", encoding="utf-8") as handle:
                handle.write(json.dumps(row, default=numpy_encoder) + "\n")
            return row
        return evt

    def _build_run_meta(
        self,
        *,
        operator_id="",
        notes="",
        camera_profile_name="",
        default_sequence_length=10,
        default_sequence_interval_ms=500,
    ):
        meta = {}
        manager = getattr(self.model, "calibration_manager", None)
        builder = getattr(manager, "_build_recorder_meta", None)
        if callable(builder):
            try:
                payload = builder()
                if isinstance(payload, dict):
                    meta.update(payload)
            except Exception:
                pass

        experiment_model = getattr(self.model, "experiment_model", None)
        experiment_path = getattr(experiment_model, "experiment_dir_path", None)
        meta.update(
            {
                "operator_id": str(operator_id or os.getenv("USERNAME") or "unknown"),
                "notes": str(notes or ""),
                "experiment_path": str(experiment_path or ""),
                "camera_profile_name": str(camera_profile_name or "refuel_camera_default"),
                "image_format": "png",
                "raw_only": True,
                "save_online_analysis_seed": True,
                "default_sequence_length": int(max(1, int(default_sequence_length))),
                "default_sequence_interval_ms": int(max(1, int(default_sequence_interval_ms))),
            }
        )
        return meta

    def start_session(
        self,
        *,
        operator_id="",
        notes="",
        camera_profile_name="",
        default_sequence_length=10,
        default_sequence_interval_ms=500,
    ):
        if self.run_dir is not None:
            return self.run_dir

        extra_meta = self._build_run_meta(
            operator_id=operator_id,
            notes=notes,
            camera_profile_name=camera_profile_name,
            default_sequence_length=default_sequence_length,
            default_sequence_interval_ms=default_sequence_interval_ms,
        )
        run_dir = self.recorder.start_run(
            self.process_name,
            self.phase_name,
            extra_meta=extra_meta,
        )

        self.run_dir = str(run_dir)
        self.last_run_dir = str(run_dir)
        self.scenes_path = os.path.join(self.run_dir, "scenes.jsonl")
        self.frames_path = os.path.join(self.run_dir, "frames.jsonl")
        self.labels_path = os.path.join(self.run_dir, "labels.jsonl")
        self._touch_file(os.path.join(self.run_dir, "analysis.jsonl"))
        self._touch_file(self.scenes_path)
        self._touch_file(self.frames_path)
        self._touch_file(self.labels_path)
        self._scene_records = []
        self._frame_records = []
        self._frames_by_id = {}
        self._current_scene = None
        self._last_frame_id = None
        self._scene_index = 0
        self._sequence_index = 0
        self._session_meta = {
            "run_id": os.path.basename(self.run_dir),
            **extra_meta,
        }
        self._append_event(
            "session_started",
            {
                "operator_id": extra_meta.get("operator_id"),
                "notes": extra_meta.get("notes"),
                "camera_profile_name": extra_meta.get("camera_profile_name"),
            },
        )
        return self.run_dir

    def _finalize_current_scene(self, *, reason="scene_ended"):
        if self._current_scene is None:
            return None

        scene = self._current_scene
        scene["ended_at_utc"] = self._now_utc()
        accepted = 0
        rejected = 0
        for record in self._frame_records:
            if record.get("scene_id") != scene.get("scene_id"):
                continue
            if record.get("rejected"):
                rejected += 1
            else:
                accepted += 1
        scene["accepted_frame_count"] = int(accepted)
        scene["rejected_frame_count"] = int(rejected)
        self._sync_scene_file()
        self._append_event(
            "scene_ended",
            {
                "scene_id": scene.get("scene_id"),
                "reason": str(reason or "scene_ended"),
                "accepted_frame_count": int(accepted),
                "rejected_frame_count": int(rejected),
            },
        )
        self._current_scene = None
        return dict(scene)

    def start_scene(
        self,
        *,
        purpose,
        scene_tags=None,
        notes="",
        geometry_expected_static=True,
        machine_context=None,
        camera_context=None,
    ):
        if self.run_dir is None:
            raise RuntimeError("Start a dataset session before starting a scene.")

        if self._current_scene is not None:
            self._finalize_current_scene(reason="replaced_by_new_scene")

        self._scene_index += 1
        scene_id = f"scene_{self._scene_index:03d}"
        scene = {
            "schema_version": int(self.SCHEMA_VERSION),
            "scene_id": scene_id,
            "scene_index": int(self._scene_index),
            "started_at_utc": self._now_utc(),
            "ended_at_utc": None,
            "purpose": str(purpose or "nominal_static"),
            "geometry_expected_static": bool(geometry_expected_static),
            "notes": str(notes or ""),
            "scene_tags": self._dedupe_tags(scene_tags),
            "machine_context": self._json_copy(machine_context),
            "camera_context": self._json_copy(camera_context),
            "accepted_frame_count": 0,
            "rejected_frame_count": 0,
        }
        self._scene_records.append(scene)
        self._current_scene = scene
        self._sync_scene_file()
        self._append_event(
            "scene_started",
            {
                "scene_id": scene_id,
                "purpose": scene["purpose"],
                "scene_tags": list(scene["scene_tags"]),
            },
        )
        return dict(scene)

    def next_sequence_id(self):
        self._sequence_index += 1
        return f"seq_{self._sequence_index:03d}"

    def capture_frame(
        self,
        image,
        *,
        frame_kind,
        sequence_id="",
        sequence_index=1,
        sequence_length=1,
        frame_tags=None,
        notes="",
        machine_context=None,
        camera_context=None,
        analysis_seed=None,
    ):
        if self.run_dir is None:
            raise RuntimeError("Start a dataset session before capturing frames.")
        if self._current_scene is None:
            raise RuntimeError("Start a scene before capturing frames.")
        if image is None:
            raise ValueError("Cannot capture an empty refuel dataset frame.")

        raw_shape = list(np.asarray(image).shape)
        cap = self.recorder.save_capture_image(
            image,
            role="raw",
            file_ext="png",
            metadata={"scene_id": self._current_scene["scene_id"]},
        )
        if cap is None:
            raise RuntimeError("Failed to save refuel dataset frame.")

        frame_id = f"frame_{int(cap['capture_index']):06d}"
        record = {
            "schema_version": int(self.SCHEMA_VERSION),
            "frame_id": frame_id,
            "scene_id": self._current_scene["scene_id"],
            "capture_id": cap["capture_id"],
            "capture_index": int(cap["capture_index"]),
            "image_relpath": cap["image_relpath"],
            "captured_at_utc": cap["captured_at_utc"],
            "raw_image_shape": raw_shape,
            "frame_kind": str(frame_kind or "single"),
            "sequence_id": str(sequence_id or ""),
            "sequence_index": int(sequence_index) if sequence_index is not None else None,
            "sequence_length": int(sequence_length) if sequence_length is not None else None,
            "frame_tags": self._dedupe_tags(frame_tags),
            "notes": str(notes or ""),
            "machine_context": self._json_copy(machine_context),
            "camera_context": self._json_copy(camera_context),
            "rejected": False,
            "rejected_at_utc": None,
            "reject_reason": "",
        }
        self._frame_records.append(record)
        self._frames_by_id[frame_id] = record
        self._last_frame_id = frame_id
        self._sync_frame_file()
        self._append_event(
            "frame_captured",
            {
                "frame_id": frame_id,
                "scene_id": record["scene_id"],
                "frame_kind": record["frame_kind"],
                "sequence_id": record["sequence_id"],
            },
        )

        if isinstance(analysis_seed, dict) and analysis_seed.get("predicted_status") not in (None, "", "not_found"):
            payload = {
                "kind": "refuel_dataset_seed",
                "frame_id": frame_id,
                "capture_id": cap["capture_id"],
                "capture_index": int(cap["capture_index"]),
                "image_relpath": cap["image_relpath"],
                **self._json_copy(analysis_seed),
            }
            self.recorder.append_analysis(payload)

        return dict(record)

    def reject_last_capture(self, *, reason=""):
        if not self._last_frame_id:
            return None
        record = self._frames_by_id.get(self._last_frame_id)
        if record is None or bool(record.get("rejected")):
            return None

        record["rejected"] = True
        record["rejected_at_utc"] = self._now_utc()
        record["reject_reason"] = str(reason or "")
        self._sync_frame_file()
        evt = self._append_event(
            "frame_rejected",
            {
                "frame_id": record["frame_id"],
                "scene_id": record["scene_id"],
                "reason": str(reason or ""),
            },
        )
        for scene in self._scene_records:
            if scene.get("scene_id") == record.get("scene_id"):
                scene["rejected_frame_count"] = int(scene.get("rejected_frame_count", 0)) + 1
                break
        self._sync_scene_file()
        return evt

    def end_session(self, *, outcome="completed", error_message=""):
        if self.run_dir is None:
            return None

        self._finalize_current_scene(reason="session_ended")
        accepted_frames = len([row for row in self._frame_records if not bool(row.get("rejected"))])
        self._append_event(
            "session_ended",
            {
                "scene_count": len(self._scene_records),
                "accepted_frame_count": int(accepted_frames),
                "total_frame_count": len(self._frame_records),
            },
        )
        self.recorder.finalize_run(str(outcome or "completed"), error_message=str(error_message or ""))
        last_dir = self.run_dir
        self.last_run_dir = last_dir
        self.reset_state()
        self.last_run_dir = last_dir
        return last_dir


